#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

template <class T>
class SegTreeMax {
    int n;
    vector<T> tree;
    T init_val;

    void build(int node, int l, int r, T init) {
        if (l == r) {
            tree[node] = init;
            return;
        }
        int mid = (l + r) / 2;
        build(2*node+1, l, mid, init);
        build(2*node+2, mid+1, r, init);
        tree[node] = max(tree[2*node+1], tree[2*node+2]);
    }

    void update(int idx, T val, int node, int l, int r) {
        if (l == r) {
            tree[node] = max(tree[node], val);
            return;
        }
        int mid = (l + r) / 2;
        if (idx <= mid) 
            update(idx, val, 2*node+1, l, mid);
        else 
            update(idx, val, 2*node+2, mid+1, r);
        tree[node] = max(tree[2*node+1], tree[2*node+2]);
    }

    T query(int ql, int qr, int node, int l, int r) {
        if (ql > qr) return init_val;
        if (ql <= l && r <= qr) {
            return tree[node];
        }
        int mid = (l + r) / 2;
        T res = init_val;
        if (ql <= mid) {
            T left_q = query(ql, qr, 2*node+1, l, mid);
            res = max(res, left_q);
        }
        if (qr > mid) {
            T right_q = query(ql, qr, 2*node+2, mid+1, r);
            res = max(res, right_q);
        }
        return res;
    }

public:
    SegTreeMax(int size, T init) : n(size), init_val(init) {
        tree.assign(4 * n, init_val);
    }

    void update(int idx, T val) {
        update(idx, val, 0, 0, n-1);
    }

    T query(int ql, int qr) {
        return query(ql, qr, 0, 0, n-1);
    }
};

