#include <vector>
#include <stack>
#include <algorithm>
using namespace std;

long long solve(vector<long long> weight) {
    int n = weight.size();
    if (n < 2) {
        return 0;
    }

    vector<int> left_greater(n, -1);
    stack<int> st;
    for (int i = 0; i < n; i++) {
        while (!st.empty() && weight[st.top()] <= weight[i]) {
            st.pop();
        }
        if (!st.empty()) {
            left_greater[i] = st.top();
        }
        st.push(i);
    }

    vector<long long> dp(n, 0);
    vector<long long> max_dp(n, 0);
    dp[0] = 0;
    max_dp[0] = 0;

    for (int i = 1; i < n; i++) {
        dp[i] = dp[i-1];
        if (left_greater[i] != -1) {
            int j0 = left_greater[i];
            long long M = (j0 > 0) ? max_dp[j0-1] : 0;
            if (M + 1 > dp[i]) {
                dp[i] = M + 1;
            }
        }

        if (i == 0) {
            max_dp[i] = dp[i];
        } else {
            if (dp[i] > max_dp[i-1]) {
                max_dp[i] = dp[i];
            } else {
                max_dp[i] = max_dp[i-1];
            }
        }
    }

    return dp[n-1];
}
```

### Explanation
1. **Preprocessing Left Greater Elements**: The stack is used to efficiently find the nearest previous element greater than the current element for each position in the array. This step ensures we can quickly determine valid starting points for balanced shipments.
2. **Dynamic Programming Setup**: The `dp` array starts with `dp[0] = 0` since a single element cannot form a balanced shipment. For each subsequent element, we consider both skipping it (carrying forward the previous DP value) and including it as the end of a new shipment (if a valid starting point exists).
3. **Max DP Array**: The `max_dp` array helps in efficiently determining the best state from which to form a new shipment by storing the maximum DP value encountered up to each position.
4. **Result Extraction**: The value `dp[n-1]` gives the maximum number of non-overlapping balanced shipments achievable for the entire array, leveraging the preprocessed data and dynamic programming to ensure optimal performance.
